package automation

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/automation"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/events"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type OnPostDeleteProxy struct {
	automation.UnimplementedOnPostDeleteServer
	client automation.OnPostDeleteClient
}

func init() {
	proxyutil.Register(&automation.OnPostDelete_ServiceDesc, NewOnPostDeleteProxy)
}
func NewOnPostDeleteProxy(cc grpc.ClientConnInterface) automation.OnPostDeleteServer {
	return &OnPostDeleteProxy{client: automation.NewOnPostDeleteClient(cc)}
}
func (p *OnPostDeleteProxy) OnPostDelete(ctx context.Context, in *events.PostDelete) (*automation.HandlerResult, error) {
	return proxyutil.ProxyMethod[events.PostDelete, automation.HandlerResult](p.client.OnPostDelete)(ctx, in)
}
